var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신이 왜…… 여기 있는 거지?","JPN":"あなたがなぜ……ここに？","ENG":"What are you... doing here?","TWN":"你為什麼……會在這裡？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅.","JPN":"ルードヴィヒ。","ENG":"Ludwig.","TWN":"路易。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이곳은 내 저택이네.","JPN":"ここは私の邸宅だ。","ENG":"This is my mansion.","TWN":"這裡是我的屋子啊。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"악령 들린 수녀라니, 얼마나 끔찍한 일인가?","JPN":"悪霊に憑りつかれたシスターとは、なんと恐ろしい。","ENG":"A nun possessed by an evil spirit... What a dreadful sight.","TWN":"修女被惡靈附身，多麼可怕的事情啊！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네가 퇴마에 어려움을 겪는 것 같아 내가 뒤를 노렸지.","JPN":"君が退魔に手こずっているようだったから、後ろから狙っていたのさ。","ENG":"It seemed like you were struggling with the exorcism, so I took the liberty of finishing the job.","TWN":"看你在驅魔上遇到困難，我就從後面偷襲了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이……자식이…….","JPN":"この……野郎……","ENG":"You... bastard...","TWN":"你這傢伙！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L12_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"왜 화를 내는 거지?","JPN":"なぜ怒る？","ENG":"Why are you mad?","TWN":"為什麼生氣呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이 수녀에게 악령이 들렸다고 한 건 자네 아닌가?","JPN":"このシスターに悪霊が憑りついていると言ったのは君だろう？","ENG":"Weren't you the one who said the nun was possessed?","TWN":"不是你說這個修女被惡靈附身了嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"영지의 주인으로서, 이를 두고 볼 수만은 없었네만.","JPN":"領主として見過ごすわけにはいかない。","ENG":"As the owner of this estate, I couldn't just stand by and watch.","TWN":"作為領地的主人，我不能坐視不管。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"분명 당신은 침식 증후군에…….","JPN":"確かあなたは、侵食症候群に……","ENG":"But you have Corruption Syndrome...","TWN":"你肯定患有侵蝕症候群……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"내가 저택 밖에서 자네를 기다리고만 있을 줄 알았나?","JPN":"私が邸宅の外でいつまでも君を待っているとでも思ったのかね？","ENG":"Did you really think I was just waiting for you outside?","TWN":"你以為我會一直在屋子外等你嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"악령이라는 핑계로 잘도 저택을 쏘다니더군.","JPN":"悪霊を言い訳に、この邸宅の中を好き勝手歩き回ったようだね。","ENG":"You had no problem wandering through my mansion, using \\"exorcism\\" as an excuse.","TWN":"以驅除惡靈為藉口，竟然在屋子裡到處亂竄。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"이 이상은 선을 넘었다고 판단한 것뿐이네.","JPN":"これ以上は看過できないと判断しただけさ。","ENG":"I simply decided you had crossed the line.","TWN":"我只是認為你已經越界了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……그 부분은 업무상 착오로 사과드립니다.","JPN":"……そこらへんの失礼な行動はお詫びいたします。","ENG":"...Fine. I'll admit that was a mistake on my part.","TWN":"……對於那部分的工作失誤，我深表歉意。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"다만, 왜 여기 어보미네이션이 있는 거죠?","JPN":"しかし、なぜここにアボミネーションがいるのですか？","ENG":"But then, why is there an Abomination here?","TWN":"不過，為什麼這裡會有憎惡呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택에 도시는 왜 나타난 건데요?","JPN":"邸宅に都市が現れた理由は？","ENG":"And why is there also a city inside this mansion?","TWN":"你為什麼會出現在屋子裡？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"의뢰인의 사생활을 묻는 건 계약에 없었다만.","JPN":"依頼人のプライベートを探ることは、契約になかったはずだが。","ENG":"Asking about a client's private affairs wasn't part of our contract.","TWN":"合約裡可沒有能詢問委託人私生活的條款。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"닥치고 말해!","JPN":"いい加減白状しなさい！","ENG":"Cut the crap and talk!","TWN":"閉嘴！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"바로 자네 덕분이네.","JPN":"それは他でもない、君のおかげだ。","ENG":"It's all thanks to you.","TWN":"正是托你的福！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐……라고?","JPN":"なん、だと……？","ENG":"What...?","TWN":"你說……什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"설마 내 피를…… 이용해서?","JPN":"まさか、私の血を……使って？","ENG":"You mean... you used my blood?","TWN":"難道是利用了……我的血？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"정답이네.","JPN":"正解だ。","ENG":"Correct.","TWN":"……沒錯。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네 핏속에 담긴 인자는 발현도가 높더군.","JPN":"君の血液に含まれているファクターは、発現度の高いものだったよ。","ENG":"The factor in your blood has an exceptionally high manifestation rate.","TWN":"你血液中的因子可是立了大功啊。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"덕분에 내가 연구하고 싶었던 이상 침식 현상을 재현하는 데 성공했네.","JPN":"おかげで私が研究したかった異常侵食現象を再現することができた。","ENG":"Thanks to that, I succeeded in recreating the Aberrant Counterside Effect I wanted to study.","TWN":"多虧了你，我成功重現了我一直想研究的異常侵蝕現象。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 아까 발견했던 시체는…….","JPN":"じゃあ、さっき見つけた死体は……","ENG":"Then, that corpse I found earlier...","TWN":"那麼剛才發現的屍體是……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그래. 내 실험체 중 하나였지.","JPN":"ああ、私の実験体のひとつだよ。","ENG":"Yes. It was one of my test subjects.","TWN":"對，他曾是我的實驗品。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"쓸모없는 실패작이라 곧장 폐기했지만 말일세.","JPN":"役に立たない失敗作だったから、すぐに廃棄したがね。","ENG":"A worthless failure, so I disposed of it.","TWN":"因為是沒用的失敗品，所以就廢棄了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"왜 이상 침식 현상 같은 걸 연구하는 거야?","JPN":"なぜ異常侵食現象なんか研究してる？","ENG":"Why would you even want to research something like the Aberrant Counterside Effect?","TWN":"為什麼要研究這種異常侵蝕現象？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"합의체의 사주인가?","JPN":"合意体の差し金？","ENG":"Are you working with the Northern Union?","TWN":"是和議會的指使嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"평생 만지지 못할 돈이라도 약속한 거냐고!","JPN":"一生手に入らないぐらいの金でも約束されたわけ！？","ENG":"Did they promise you a fortune beyond your wildest dreams?!","TWN":"他們答應要給你我一輩子都賺不到的錢嗎？！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네와는 다르게, 나는 돈에 연연하지 않네.","JPN":"君と違って、私は金に執着しない。","ENG":"Unlike you, I'm not obsessed with money.","TWN":"和你不一樣，我對錢沒有那麼執著。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"당연히 합의체의 제안도 거절했지.","JPN":"当然、合意体の提案も断ったさ。","ENG":"Naturally, I rejected their proposal.","TWN":"當然，我拒絕了和議會的提議。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그들의 키메라는 훌륭하지만…… 내가 지향하는 바는 아니었거든.","JPN":"彼らのキメラは確かにいい出来だが……私が目指しているものとは違ってね。","ENG":"Their chimeras are impressive... but not aligned with my goals.","TWN":"他們的奇美拉很出色……但那不是我所追求的。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 도대체 왜…….","JPN":"じゃあ、いったいなぜ……","ENG":"Then why...?","TWN":"那到底是為什麼……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나는 침식을 정복하고 싶었네.","JPN":"私は侵食を征服したかった。","ENG":"I wanted to conquer the Corruption.","TWN":"我想征服侵蝕。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나 역시 침식 증후군으로 고통받고 있는 몸이었으니까.","JPN":"私も、侵食症候群に苦しめられている身だからね。","ENG":"After all, I suffer from Corruption Syndrome myself.","TWN":"我也飽受侵蝕症候群折磨。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 이거랑 무슨 상관인데!","JPN":"それとは関係ないでしょう！","ENG":"And how does this help with that?!","TWN":"那跟這個有什麼關係！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"성미가 급하군.","JPN":"そう急かすな。","ENG":"How impatient.","TWN":"個性真急。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"마음 같아선 자네와 느긋하게 차나 한잔하면서 이야기하고 싶지만…….","JPN":"君とはお茶でもしながらゆっくり話し合いたいのだが……","ENG":"Ideally, I'd sit down for a cup of tea with you and explain everything at a leisurely pace...","TWN":"這種情況下，我雖然想和你悠閒地喝杯茶聊聊天……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"허락된 시간이 많지 않아서 말이지.","JPN":"許された時間があまり長くないんだ。","ENG":"But I don't have the time for that luxury.","TWN":"但沒有多少時間了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 폼 잡지 말고 어서 말해.","JPN":"じゃあ格好つけないでさっさと言いなよ！","ENG":"Then stop wasting time and talk already.","TWN":"那就別裝模作樣，快說吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"자네도 알다시피, 침식 증후군은 치료할 수 없는 병일세.","JPN":"君も知っている通り、侵食症候群は治療法のない病だ。","ENG":"As you know, Corruption Syndrome is incurable.","TWN":"你也知道，侵蝕症候群是無法治癒的病。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나도 한때, 모든 의욕을 잃고 죽음만을 기다리던 시절이 있었어.","JPN":"私もかつてはすべての意欲を失くし、死を待つだけだった。","ENG":"There was a time when I lost all motivation and simply waited for death.","TWN":"我也曾有過失去求生意志，只等待死亡的時侯。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"어느 날이었네.","JPN":"そんなある日。","ENG":"And then, one day...","TWN":"但是某一天……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그런 나에게 구원의 빛이 내려왔어.","JPN":"私に救いの光が現れたのさ。","ENG":"A light of salvation shone upon me.","TWN":"這樣的我，得到了救贖之光。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"전설의 비약. 엘릭서였지.","JPN":"伝説の秘薬、エリクサーだった。","ENG":"The legendary potion. The Elixir.","TWN":"那是傳說中的藥劑——聖水。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};